import{_ as e,o as r,c as o,ag as s}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Network Protocols","description":"","frontmatter":{},"headers":[],"relativePath":"theory/networks/protocols.md","filePath":"theory/networks/protocols.md"}'),a={name:"theory/networks/protocols.md"};function d(n,t,i,l,c,h){return r(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="network-protocols" tabindex="-1">Network Protocols <a class="header-anchor" href="#network-protocols" aria-label="Permalink to &quot;Network Protocols&quot;">​</a></h1><p>A protocol is a set of rules that governs communication between devices. Without protocols, a Windows laptop, an Android phone, a Linux server, and a Mac could not exchange a single byte. Protocols make interoperability possible.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11+</p><p>Network protocols are introduced in Grade 11. SSL/TLS and network security protocols extend into Grade 12.</p></div><hr><h2 id="what-is-a-protocol" tabindex="-1">What is a Protocol? <a class="header-anchor" href="#what-is-a-protocol" aria-label="Permalink to &quot;What is a Protocol?&quot;">​</a></h2><p>A <strong>network protocol</strong> is a set of standardised rules that define:</p><ul><li>The <strong>format</strong> of data packets (how data is structured)</li><li>The <strong>sequence</strong> of messages (who sends first, how errors are acknowledged)</li><li><strong>Error detection</strong> and correction methods</li><li><strong>Speed</strong> and flow control</li></ul><p><strong>Analogy:</strong> A protocol is like a language. Two people can only communicate if they use the same language and follow the same grammar rules.</p><hr><h2 id="the-tcp-ip-model" tabindex="-1">The TCP/IP Model <a class="header-anchor" href="#the-tcp-ip-model" aria-label="Permalink to &quot;The TCP/IP Model&quot;">​</a></h2><p>The <strong>TCP/IP model</strong> is the fundamental protocol suite of the internet. It organises protocols into four layers:</p><table tabindex="0"><thead><tr><th>Layer</th><th>Protocols</th><th>Function</th></tr></thead><tbody><tr><td><strong>Application</strong></td><td>HTTP, HTTPS, FTP, SMTP, DNS, DHCP</td><td>What the application does with data</td></tr><tr><td><strong>Transport</strong></td><td>TCP, UDP</td><td>End-to-end delivery, error correction</td></tr><tr><td><strong>Internet</strong></td><td>IP</td><td>Addressing and routing between networks</td></tr><tr><td><strong>Network Access</strong></td><td>Ethernet, Wi-Fi</td><td>Physical transmission of data</td></tr></tbody></table><hr><h2 id="core-protocols-—-table" tabindex="-1">Core Protocols — Table <a class="header-anchor" href="#core-protocols-—-table" aria-label="Permalink to &quot;Core Protocols — Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Protocol</th><th>Full Name</th><th>Port</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>HTTP</strong></td><td>HyperText Transfer Protocol</td><td>80</td><td>Transfers web pages (unencrypted)</td></tr><tr><td><strong>HTTPS</strong></td><td>HTTP Secure</td><td>443</td><td>Encrypted HTTP using SSL/TLS</td></tr><tr><td><strong>FTP</strong></td><td>File Transfer Protocol</td><td>20, 21</td><td>Transfers files between computers</td></tr><tr><td><strong>SFTP</strong></td><td>SSH File Transfer Protocol</td><td>22</td><td>Encrypted file transfer</td></tr><tr><td><strong>SMTP</strong></td><td>Simple Mail Transfer Protocol</td><td>25</td><td>Sends email from client to server</td></tr><tr><td><strong>POP3</strong></td><td>Post Office Protocol v3</td><td>110</td><td>Downloads email to local device (removes from server)</td></tr><tr><td><strong>IMAP</strong></td><td>Internet Message Access Protocol</td><td>143</td><td>Access email on server (stays on server)</td></tr><tr><td><strong>DNS</strong></td><td>Domain Name System</td><td>53</td><td>Translates domain names to IP addresses</td></tr><tr><td><strong>DHCP</strong></td><td>Dynamic Host Configuration Protocol</td><td>67/68</td><td>Automatically assigns IP addresses</td></tr><tr><td><strong>TCP</strong></td><td>Transmission Control Protocol</td><td>—</td><td>Reliable, ordered data delivery</td></tr><tr><td><strong>UDP</strong></td><td>User Datagram Protocol</td><td>—</td><td>Fast but unreliable delivery (no error correction)</td></tr><tr><td><strong>VoIP</strong></td><td>Voice over IP</td><td>various</td><td>Voice calls over internet (e.g. Skype, WhatsApp calls)</td></tr><tr><td><strong>SSH</strong></td><td>Secure Shell</td><td>22</td><td>Encrypted remote terminal access</td></tr><tr><td><strong>Telnet</strong></td><td>—</td><td>23</td><td>Remote terminal access (unencrypted — obsolete)</td></tr></tbody></table><hr><h2 id="key-protocols-explained" tabindex="-1">Key Protocols Explained <a class="header-anchor" href="#key-protocols-explained" aria-label="Permalink to &quot;Key Protocols Explained&quot;">​</a></h2><h3 id="http-and-https" tabindex="-1">HTTP and HTTPS <a class="header-anchor" href="#http-and-https" aria-label="Permalink to &quot;HTTP and HTTPS&quot;">​</a></h3><p><strong>HTTP (HyperText Transfer Protocol)</strong></p><ul><li>Governs how web browsers request and receive web pages</li><li>Stateless — each request is independent</li><li>Unencrypted — data can be intercepted</li></ul><p><strong>HTTPS (HTTP Secure)</strong></p><ul><li>HTTP with SSL/TLS encryption</li><li>All data between browser and server is encrypted</li><li>URL begins with <code>https://</code> and shows a padlock icon</li><li>Required for any sensitive data (login, banking, purchases)</li></ul><hr><h3 id="dns-—-domain-name-system" tabindex="-1">DNS — Domain Name System <a class="header-anchor" href="#dns-—-domain-name-system" aria-label="Permalink to &quot;DNS — Domain Name System&quot;">​</a></h3><p><strong>The internet&#39;s phonebook:</strong> converts human-readable domain names into IP addresses.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>www.google.com  →  DNS lookup  →  142.250.80.100</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>How DNS works:</strong></p><ol><li>User types <code>www.school.co.za</code> in browser</li><li>Computer checks local DNS cache</li><li>If not cached, asks ISP&#39;s DNS server</li><li>DNS server finds the IP address</li><li>Computer connects to that IP address</li></ol><p><strong>DNS record types:</strong></p><ul><li><strong>A record</strong>: Domain → IPv4 address</li><li><strong>AAAA record</strong>: Domain → IPv6 address</li><li><strong>MX record</strong>: Mail exchange — where to send email for this domain</li><li><strong>CNAME</strong>: Alias — one domain points to another</li></ul><hr><h3 id="dhcp-—-dynamic-host-configuration-protocol" tabindex="-1">DHCP — Dynamic Host Configuration Protocol <a class="header-anchor" href="#dhcp-—-dynamic-host-configuration-protocol" aria-label="Permalink to &quot;DHCP — Dynamic Host Configuration Protocol&quot;">​</a></h3><p>Automatically assigns IP configuration to devices joining a network:</p><ul><li>IP address</li><li>Subnet mask</li><li>Default gateway (router address)</li><li>DNS server address</li></ul><p>Without DHCP, every device needs a manually configured static IP address.</p><hr><h3 id="tcp-vs-udp" tabindex="-1">TCP vs UDP <a class="header-anchor" href="#tcp-vs-udp" aria-label="Permalink to &quot;TCP vs UDP&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>TCP</th><th>UDP</th></tr></thead><tbody><tr><td><strong>Reliability</strong></td><td>Guaranteed delivery — acknowledgements</td><td>No guarantee — &quot;fire and forget&quot;</td></tr><tr><td><strong>Order</strong></td><td>Packets arrive in order</td><td>May arrive out of order</td></tr><tr><td><strong>Error correction</strong></td><td>Yes — retransmits lost packets</td><td>No</td></tr><tr><td><strong>Speed</strong></td><td>Slower (overhead from acknowledgements)</td><td>Faster</td></tr><tr><td><strong>Connection</strong></td><td>Connection-oriented (handshake first)</td><td>Connectionless</td></tr><tr><td><strong>Use cases</strong></td><td>Web browsing, email, file transfer</td><td>Video streaming, gaming, VoIP</td></tr></tbody></table><p><strong>Why use UDP if it&#39;s unreliable?</strong><br> In live video or gaming, a slightly corrupted frame or late packet is better than stopping to retransmit. Speed matters more than perfection.</p><hr><h3 id="ftp-—-file-transfer-protocol" tabindex="-1">FTP — File Transfer Protocol <a class="header-anchor" href="#ftp-—-file-transfer-protocol" aria-label="Permalink to &quot;FTP — File Transfer Protocol&quot;">​</a></h3><p>Used to transfer files between a client and server:</p><ul><li><code>FTP</code>: unencrypted</li><li><code>SFTP</code>: encrypted (uses SSH)</li><li><code>FTPS</code>: FTP with SSL/TLS encryption</li></ul><p>FTP is still used for web hosting and large file transfers, but SFTP is preferred for security.</p><hr><h3 id="email-protocols" tabindex="-1">Email Protocols <a class="header-anchor" href="#email-protocols" aria-label="Permalink to &quot;Email Protocols&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Protocol</th><th>Direction</th><th>Server-Side</th><th>Notes</th></tr></thead><tbody><tr><td><strong>SMTP</strong></td><td>Sending</td><td>Outgoing mail server</td><td>All email clients use SMTP to send</td></tr><tr><td><strong>POP3</strong></td><td>Receiving</td><td>Downloads to device</td><td>Removes email from server; local storage</td></tr><tr><td><strong>IMAP</strong></td><td>Receiving</td><td>Stays on server</td><td>Access from any device; sync across devices</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">POP3 vs IMAP</p><p>POP3 downloads and deletes from server — better for one device only. IMAP keeps mail on server — better for accessing email from phone, laptop, and tablet simultaneously.</p></div><hr><h2 id="ssl-tls-—-encryption-for-web" tabindex="-1">SSL/TLS — Encryption for Web <a class="header-anchor" href="#ssl-tls-—-encryption-for-web" aria-label="Permalink to &quot;SSL/TLS — Encryption for Web&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">Grade 12 Focus</p><p>SSL/TLS and public/private key encryption are Grade 12 content.</p></div><p><strong>SSL (Secure Sockets Layer)</strong> and its successor <strong>TLS (Transport Layer Security)</strong> provide:</p><ul><li><strong>Encryption</strong>: Data is scrambled — unreadable to interceptors</li><li><strong>Authentication</strong>: Certificates verify the server&#39;s identity</li><li><strong>Integrity</strong>: Data cannot be tampered with in transit</li></ul><h3 id="how-https-tls-works-simplified" tabindex="-1">How HTTPS/TLS Works (Simplified) <a class="header-anchor" href="#how-https-tls-works-simplified" aria-label="Permalink to &quot;How HTTPS/TLS Works (Simplified)&quot;">​</a></h3><ol><li>Browser connects to <code>https://bank.co.za</code></li><li>Server sends its <strong>digital certificate</strong> (contains public key)</li><li>Browser verifies the certificate (signed by a trusted Certificate Authority)</li><li>Browser generates a session key, encrypts it with the server&#39;s public key</li><li>Server decrypts it with its <strong>private key</strong></li><li>All further communication is encrypted with the session key</li></ol><h3 id="public-key-vs-private-key" tabindex="-1">Public Key vs Private Key <a class="header-anchor" href="#public-key-vs-private-key" aria-label="Permalink to &quot;Public Key vs Private Key&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Key</th><th>What it is</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Public key</strong></td><td>Shared openly — anyone can see it</td><td>Encrypts data (only the private key can decrypt)</td></tr><tr><td><strong>Private key</strong></td><td>Kept secret by the owner</td><td>Decrypts data encrypted with the matching public key</td></tr></tbody></table><hr><h2 id="wi-fi-standards-ieee-802-11" tabindex="-1">Wi-Fi Standards (IEEE 802.11) <a class="header-anchor" href="#wi-fi-standards-ieee-802-11" aria-label="Permalink to &quot;Wi-Fi Standards (IEEE 802.11)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Standard</th><th>Nickname</th><th>Max Speed</th><th>Frequency</th></tr></thead><tbody><tr><td>802.11g</td><td>Wi-Fi 3</td><td>54 Mbps</td><td>2.4 GHz</td></tr><tr><td>802.11n</td><td>Wi-Fi 4</td><td>600 Mbps</td><td>2.4/5 GHz</td></tr><tr><td>802.11ac</td><td>Wi-Fi 5</td><td>3.5 Gbps</td><td>5 GHz</td></tr><tr><td>802.11ax</td><td>Wi-Fi 6</td><td>9.6 Gbps</td><td>2.4/5/6 GHz</td></tr></tbody></table><p><strong>2.4 GHz vs 5 GHz:</strong></p><ul><li>2.4 GHz: longer range, lower speed, more interference (used by microwaves, Bluetooth)</li><li>5 GHz: shorter range, faster speed, less interference</li></ul><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Protocol</strong></td><td>Standardised rules governing network communication</td></tr><tr><td><strong>HTTP</strong></td><td>Protocol for transferring web pages (unencrypted)</td></tr><tr><td><strong>HTTPS</strong></td><td>HTTP with SSL/TLS encryption</td></tr><tr><td><strong>DNS</strong></td><td>System translating domain names to IP addresses</td></tr><tr><td><strong>DHCP</strong></td><td>Protocol automatically assigning IP addresses on a network</td></tr><tr><td><strong>TCP</strong></td><td>Reliable, ordered data transmission protocol</td></tr><tr><td><strong>UDP</strong></td><td>Fast, unreliable data transmission — no error correction</td></tr><tr><td><strong>FTP</strong></td><td>Protocol for transferring files between client and server</td></tr><tr><td><strong>SMTP</strong></td><td>Protocol for sending email</td></tr><tr><td><strong>POP3</strong></td><td>Downloads email to device; removes from server</td></tr><tr><td><strong>IMAP</strong></td><td>Accesses email on server; synchronises across devices</td></tr><tr><td><strong>SSL/TLS</strong></td><td>Encryption protocols securing internet communications</td></tr><tr><td><strong>VoIP</strong></td><td>Voice over IP — telephone calls via internet</td></tr><tr><td><strong>Public key</strong></td><td>Encryption key shared openly</td></tr><tr><td><strong>Private key</strong></td><td>Decryption key kept secret by the owner</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is the purpose of DNS?&quot;</strong> — translates human-readable domain names into IP addresses</p></li><li><p><strong>&quot;Explain the difference between TCP and UDP. When would you use each?&quot;</strong> — TCP: reliable, ordered, error correction; used for web/email. UDP: fast, no error correction; used for streaming/gaming</p></li><li><p><strong>&quot;What is the difference between POP3 and IMAP?&quot;</strong> — POP3 downloads and removes from server; IMAP keeps on server and syncs across devices</p></li><li><p><strong>&quot;Explain how HTTPS is more secure than HTTP&quot;</strong> — HTTPS uses SSL/TLS encryption; data is encrypted in transit; certificate verifies server identity</p></li><li><p><strong>&quot;What is DHCP and why is it useful?&quot;</strong> — automatically assigns IP address, subnet mask, gateway, DNS to devices; without it, every device needs manual IP configuration</p></li></ol></div>',68)])])}const u=e(a,[["render",d]]);export{g as __pageData,u as default};
